import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';

export default function DashboardCart() {
    const navigate = useNavigate();
    const { cartItems, cartSummary, updateItem, removeItem, loading } = useCart();
    const freeShippingThreshold = 100;

    const currency = (value) => new Intl.NumberFormat('en-PH', {
        style: 'currency',
        currency: 'PHP',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(Number(value || 0));

    const subtotal = Number(cartSummary?.subtotal || 0);
    const tax = Number(cartSummary?.tax || 0);
    const shipping = Number(cartSummary?.shipping || 0);
    const total = Number(cartSummary?.total || 0);
    const amountToFreeShipping = Math.max(0, freeShippingThreshold - subtotal);

    const getImage = (item) => {
        const images = item?.product?.images;

        if (Array.isArray(images) && images.length > 0) {
            return images[0];
        }

        if (typeof images === 'string') {
            try {
                const parsed = JSON.parse(images);
                if (Array.isArray(parsed) && parsed.length > 0) {
                    return parsed[0];
                }
            } catch {
                return '/images/carvex.png';
            }
        }

        return '/images/carvex.png';
    };

    const handleQuantityChange = async (cartItemId, newQuantity) => {
        if (newQuantity < 1) {
            await removeItem(cartItemId);
            return;
        }

        await updateItem(cartItemId, newQuantity);
    };

    if (loading && cartItems.length === 0 && !cartSummary) {
        return null;
    }

    return (
        <section className="customer-cart-page">
            <header className="customer-cart-header">
                <h2>Shopping Cart</h2>
            </header>

            {cartItems.length === 0 ? (
                <div className="dashboard-panel overview-empty-state">
                    <p>Your cart is empty</p>
                    <Link to="/dashboard/products" className="btn btn-primary btn-sm">
                        Continue Shopping
                    </Link>
                </div>
            ) : (
                <div className="customer-cart-layout">
                    <div className="customer-cart-items">
                        {cartItems.map((item) => (
                            <article key={item.id} className="customer-cart-item">
                                <Link to={`/products/${item.product.id}`} className="customer-cart-item__media">
                                    <img src={getImage(item)} alt={item.product.name} />
                                </Link>

                                <div className="customer-cart-item__details">
                                    <h3>{item.product.name}</h3>
                                    <p>{item.product.brand || 'CarVex'}</p>
                                    <strong>{currency(item.product.price)}</strong>
                                </div>

                                <div className="customer-cart-item__controls">
                                    <button
                                        type="button"
                                        className="customer-cart-item__remove"
                                        aria-label="Remove item"
                                        onClick={() => removeItem(item.id)}
                                    >
                                        <svg viewBox="0 0 24 24" width="18" height="18" aria-hidden="true" focusable="false">
                                            <path d="M9 3h6l1 2h4v2H4V5h4l1-2zm1 6h2v9h-2V9zm4 0h2v9h-2V9zM6 9h2v9H6V9z" fill="currentColor" />
                                        </svg>
                                    </button>

                                    <div className="customer-qty-stepper">
                                        <button type="button" onClick={() => handleQuantityChange(item.id, item.quantity - 1)}>
                                            -
                                        </button>
                                        <span>{item.quantity}</span>
                                        <button type="button" onClick={() => handleQuantityChange(item.id, item.quantity + 1)}>
                                            +
                                        </button>
                                    </div>
                                </div>
                            </article>
                        ))}
                    </div>

                    <aside className="customer-cart-summary">
                        <h3>Order Summary</h3>

                        <div className="customer-cart-summary__row">
                            <span>Subtotal</span>
                            <strong>{currency(subtotal)}</strong>
                        </div>

                        <div className="customer-cart-summary__row">
                            <span>Shipping</span>
                            <strong>{currency(shipping)}</strong>
                        </div>

                        <div className="customer-cart-summary__row">
                            <span>Tax (10%)</span>
                            <strong>{currency(tax)}</strong>
                        </div>

                        <div className="customer-cart-summary__row customer-cart-summary__row--total">
                            <span>Total</span>
                            <strong>{currency(total)}</strong>
                        </div>

                        {amountToFreeShipping > 0 ? (
                            <p className="customer-cart-summary__note">Add {currency(amountToFreeShipping)} more for free shipping</p>
                        ) : (
                            <p className="customer-cart-summary__note customer-cart-summary__note--ok">You unlocked free shipping.</p>
                        )}

                        <button
                            type="button"
                            className="btn btn-primary btn-lg btn-block"
                            onClick={() => navigate('/dashboard/checkout')}
                        >
                            Proceed to Checkout
                        </button>

                        <Link to="/dashboard/products" className="btn btn-outline-primary btn-lg btn-block">
                            Continue Shopping
                        </Link>
                    </aside>
                </div>
            )}
        </section>
    );
}